import jwt
import datetime
import base64
import hashlib
import os
SECRET_KEY = os.urandom(256)  # Generate secret key once and keep it secure
ALGORITHM = "HS256"

def generate_jwt(user_id, role):
    payload = {
        'exp': datetime.datetime.utcnow() + datetime.timedelta(minutes=30),  # Token expiration time (in this example it's set for 30 minutes)
        'iat': datetime.datetime.utcnow(),  # Issue time
        'sub': user_id,
        'role': role,
    }

    encoded_payload = jwt.encode(
        payload, SECRET_KEY, algorithm=ALGORITHM)

    return encoded_payload.decode('utf-8')